import { describe, expect, it, vi } from "vitest";
const mockClearActiveStudioSession = vi.fn();
const mockCloseStudio = vi.fn().mockResolvedValue({ ok: true });
// biome-ignore lint/suspicious/noExplicitAny: test capture of the poll opts
let capturedPollOpts = null;
const mockPollAgentSessionEvents = vi.fn((...args) => {
    capturedPollOpts = args[0];
    // Never resolves on its own; the test drives onEvent manually.
    return new Promise(() => { });
});
vi.mock("../activeStudioSession.js", () => ({
    clearActiveStudioSession: (...args) => mockClearActiveStudioSession(...args),
}));
vi.mock("../agentSessionChannel.js", () => ({
    closeStudio: (...args) => mockCloseStudio(...args),
    pollAgentSessionEvents: (...args) => mockPollAgentSessionEvents(...args),
}));
vi.mock("../config.js", () => ({
    getConfig: () => ({ serviceUrl: "https://test.invalid", apiKey: "test-key" }),
    hasCredentials: () => true,
}));
const SESSION = "11111111-1111-4111-8111-111111111111";
describe("runCloseStudio", () => {
    it("polls from the stream tip so a replayed historical session-closed can't clear a live pointer", async () => {
        // fetchStreamTip reads the latest event id from /api/studio/events; the tip
        // is the LAST event's id.
        const fetchMock = vi.fn().mockResolvedValue({
            ok: true,
            json: async () => ({ events: [{ id: "100-0" }, { id: "200-5" }] }),
        });
        vi.stubGlobal("fetch", fetchMock);
        const exitMock = vi
            .spyOn(process, "exit")
            .mockImplementation((() => undefined));
        const savedArgv = process.argv;
        process.argv = ["node", "closeStudio.js", SESSION];
        try {
            const { runCloseStudio } = await import("./closeStudio.js");
            const run = runCloseStudio();
            await vi.waitFor(() => expect(capturedPollOpts).not.toBeNull());
            // The load-bearing assertion: the poll starts AFTER the pre-close tip, so
            // any session-closed already in history (id <= tip) is never seen.
            expect(capturedPollOpts.startCursor).toBe("200-5");
            expect(fetchMock).toHaveBeenCalledOnce();
            expect(mockCloseStudio).toHaveBeenCalled();
            // A fresh session-closed (produced by our own close) confirms it -> clear.
            capturedPollOpts.onEvent({ type: "studio:session-closed", data: {} });
            await run;
            expect(mockClearActiveStudioSession).toHaveBeenCalledWith(SESSION, {
                force: true,
            });
        }
        finally {
            process.argv = savedArgv;
            exitMock.mockRestore();
            vi.unstubAllGlobals();
        }
    });
});
